BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?blockName ?attrName ?attrType ?attrTypeName ?superClassName WHERE {
  VALUES ?blockName { "Peak%20Power%20Limit%20Requirement%20JPL" "Peak%20Power%20Limit%20Requirement%20TMT" }
  ?block vocab:NamedElement_name ?blockName .
  ?block rdf:type vocab:block .

  OPTIONAL {
    ?block vocab:StructuredClassifier_ownedAttribute ?attr .
    ?attr vocab:NamedElement_name ?attrName .
    OPTIONAL {
      ?attr vocab:TypedElement_type ?attrTypeElem .
      ?attrTypeElem vocab:NamedElement_name ?attrTypeName .
      ?attrTypeElem rdf:type ?attrType .
    }
  }

  OPTIONAL {
    ?block vocab:Class_superClass ?superClass .
    ?superClass vocab:NamedElement_name ?superClassName .
  }
}
ORDER BY ?blockName ?attrName

