BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?blockName ?vpName ?vpType ?defaultVal ?defaultValType WHERE {
  ?block rdf:type vocab:block .
  ?block vocab:NamedElement_name ?blockName .
  FILTER(?blockName = "Peak%20Power%20Limit%20Requirement%20JPL" || ?blockName = "Peak%20Power%20Limit%20Requirement%20TMT")
  ?block vocab:Element_ownedElement ?vp .
  ?vp rdf:type vocab:value%20property .
  ?vp vocab:NamedElement_name ?vpName .
  OPTIONAL {
    ?vp vocab:TypedElement_type ?vpTypeElem .
    ?vpTypeElem vocab:NamedElement_name ?vpType .
  }
  OPTIONAL {
    ?vp vocab:Property_defaultValue ?dv .
    ?dv vocab:LiteralString_value ?defaultVal .
  }
  OPTIONAL {
    ?vp vocab:Property_defaultValue ?dv2 .
    ?dv2 rdf:type ?defaultValType .
  }
}
ORDER BY ?blockName ?vpName

